import React from 'react';
import * as THREE from 'three';

import { playCameraCinematic, requestCameraCloseUp, restoreCameraCloseUp, useCharacterStore, useStateSystem } from 'gaesup-world';

const panelStyle: React.CSSProperties = {
  position: 'fixed',
  right: 360,
  bottom: 104,
  zIndex: 20,
  display: 'flex',
  gap: 8,
};

const buttonStyle: React.CSSProperties = {
  minHeight: 36,
  padding: '0 12px',
  border: '1px solid rgba(255,255,255,0.24)',
  borderRadius: 6,
  background: 'rgba(16, 20, 28, 0.78)',
  color: '#fff',
  fontSize: 13,
  fontWeight: 700,
  cursor: 'pointer',
};

export function CloseUpControls() {
  const { activeState, updateActiveState } = useStateSystem();

  const handleCloseUp = () => {
    const target = activeState.position.clone();
    target.y += 1.25;
    requestCameraCloseUp(target, {
      focusDistance: 3.8,
      focusLerpSpeed: 7.5,
      fov: 42,
      enableCollision: false,
    });
  };

  const handleCinematic = () => {
    const origin = activeState.position.clone();
    const head = origin.clone();
    head.y += 1.3;
    const left = head.clone();
    left.x -= 2.4;
    const forward = head.clone();
    forward.z -= 3.2;

    playCameraCinematic([
      { kind: 'fade', direction: 'in', color: '#05070c', durationMs: 180 },
      { kind: 'expression', face: 'surprised', durationMs: 160 },
      { kind: 'equip', slot: 'weapon', itemId: 'starter-sword', durationMs: 120 },
      { kind: 'closeUp', target: head, durationMs: 620, focusDistance: 4.2, focusLerpSpeed: 7.5, fov: 44 },
      { kind: 'dolly', target: forward, fromDistance: 6.8, toDistance: 3.8, durationMs: 720, focusLerpSpeed: 8, fov: 40 },
      { kind: 'teleport', position: origin.clone().add(new THREE.Vector3(0, 0, -1.2)), durationMs: 120 },
      { kind: 'orbit', target: left, radius: 5.2, angleDeg: 38, height: 0.35, durationMs: 700, focusLerpSpeed: 7, fov: 48 },
      { kind: 'shake', intensity: 0.12, durationMs: 160 },
      { kind: 'animation', name: 'cinematic-wave', durationMs: 80 },
      { kind: 'event', name: 'examples:cinematic-complete', payload: { source: 'CloseUpControls' }, durationMs: 20 },
      { kind: 'fade', direction: 'out', color: '#05070c', durationMs: 180 },
      { kind: 'restore' },
    ], {
      onTeleport: (position) => {
        updateActiveState({ position });
      },
      onEvent: (name) => {
        if (name === 'examples:cinematic-complete') {
          useCharacterStore.getState().setFace('smile');
        }
      },
    });
  };

  return (
    <div style={panelStyle}>
      <button style={buttonStyle} type="button" onClick={handleCloseUp}>
        Close-up
      </button>
      <button style={buttonStyle} type="button" onClick={restoreCameraCloseUp}>
        Restore
      </button>
      <button style={buttonStyle} type="button" onClick={handleCinematic}>
        Cinematic
      </button>
    </div>
  );
}
